solutions.python:
import sys

class Solution:
    def gcd(self, a, b):
        def recursive_gcd(x, y):
            if y == 0:
                return x
            else:
                return recursive_gcd(y, x % y)

        return recursive_gcd(a, b)

if __name__ == "__main__":
    a = int(sys.stdin.readline())
    b = int(sys.stdin.readline())
    print(Solution().gcd(a, b))

